import{indicarProdutosNoCarrinhoEFavoritos}from"./indicador-notificacao.js";function ouvinteBotaoFavoritar(){var o=document.querySelectorAll(".botao-favoritos i");let r=JSON.parse(localStorage.getItem("meusFavoritos"))||[];o.forEach(t=>{t.addEventListener("click",()=>{let e=t.closest(".card").dataset.id;document.querySelector(".confirmacao-adicao-carrinho");if(console.log("ID do produto clicado:",e),r.includes(e)){r=r.filter(o=>o!==e),t.style.color="inherit";let o=document.querySelector(".confirmacao-adicao-carrinho");o.querySelector(".container h5").innerHTML='<i class="fas fa-times-circle me-2" style="color: #dc3545;"></i>Produto removido dos favoritos',o.style.display="flex",setTimeout(function(){o.querySelector(".container").style.transform="translateY(0)"},200),setTimeout(function(){o.querySelector(".container").style.transform="translateY(130%)",setTimeout(function(){o.style.display="none"},600)},1e3)}else{r.push(e),t.style.color="gold";let o=document.querySelector(".confirmacao-adicao-carrinho");o.querySelector(".container h5").innerHTML='<i class="fas fa-check-circle me-2" style="color: #28a745;"></i>Produto adicionado aos favoritos',o.style.display="flex",setTimeout(function(){o.querySelector(".container").style.transform="translateY(0)"},200),setTimeout(function(){o.querySelector(".container").style.transform="translateY(130%)",setTimeout(function(){o.style.display="none"},600)},1e3)}localStorage.setItem("meusFavoritos",JSON.stringify(r)),indicarProdutosNoCarrinhoEFavoritos()})})}export{ouvinteBotaoFavoritar};